function activate(context) {
  context.ui.addToolbarButton({
    icon: 'braces',
    label: context.t('toolbar.label'),
    onClick: function () {
      var text = context.editor.getValue();
      try {
        var parsed = JSON.parse(text);
        context.editor.setValue(JSON.stringify(parsed, null, 2));
        context.ui.showNotification(context.t('notify.ok'), 'success');
      } catch (e) {
        context.ui.showNotification(context.t('notify.err'), 'error');
      }
    },
  });
}
